function clean(v){return String(v??'').trim()}
function esc(v){return clean(v).replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}

function normalizeHeader(v){return String(v??'').replace(/^\uFEFF/,'').normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().replace(/[^a-z0-9]+/g,' ').trim()}
function parseCSV(text){const rows=[];let row=[],value='',quoted=false;for(let i=0;i<text.length;i++){const ch=text[i],next=text[i+1];if(ch==='"'&&quoted&&next==='"'){value+='"';i++}else if(ch==='"'){quoted=!quoted}else if(ch===','&&!quoted){row.push(value);value=''}else if((ch==='\n'||ch==='\r')&&!quoted){if(ch==='\r'&&next==='\n')i++;if(value||row.length){row.push(value);rows.push(row);row=[];value=''}}else value+=ch}if(value||row.length){row.push(value);rows.push(row)}return rows}
function csvToObjects(csv){const rows=parseCSV(csv),headers=rows[0]||[];return rows.slice(1).map(row=>{const obj={};headers.forEach((header,index)=>obj[String(header||'').trim()]=String(row[index]??'').trim());return obj})}
