async function fetchSheetDataset(url){
 const response=await fetch(url+(url.includes('?')?'&':'?')+'cacheBust='+Date.now(),{cache:'no-store'});
 if(!response.ok)throw new Error('Error HTTP '+response.status);
 const objects=csvToObjects(await response.text()),rows=objects.map(normalizeSheetRecord).filter(d=>d.institution);
 if(!rows.length)throw new Error('La fuente no devolvió registros');
 return rows;
}
function datasetQuality(rows){
 const stable=['client','status','type','city','date','coordinates'];
 return rows.length*100+rows.reduce((score,row)=>score+stable.reduce((sum,key)=>sum+(clean(row[key])?1:0),0),0);
}
function preserveStableIdentifiers(fresh,previous){
 const prior=new Map(previous.map(row=>[(clean(row.institution)+'|'+clean(row.site)).toLowerCase(),row]));
 return fresh.map(row=>{const old=prior.get((clean(row.institution)+'|'+clean(row.site)).toLowerCase());if(!old)return row;['client','type','status'].forEach(key=>{if(!clean(row[key])&&clean(old[key]))row[key]=old[key]});return row});
}
async function loadLiveData({manual=false}={}){
 const button=$('#refreshDashboard'),original=button?.textContent;if(button){button.disabled=true;button.textContent='Actualizando…'}
 try{
  const results=await Promise.allSettled([fetchSheetDataset(SHEET_EXPORT_URL),fetchSheetDataset(SHEET_URL)]);
  const candidates=results.filter(result=>result.status==='fulfilled').map(result=>result.value);
  if(!candidates.length)throw results[0]?.reason||new Error('No se pudo consultar la hoja');
  candidates.sort((a,b)=>datasetQuality(b)-datasetQuality(a));
  DATA=preserveStableIdentifiers(candidates[0],DATA);
  DATA_UPDATED_AT=new Intl.DateTimeFormat('es-CO',{dateStyle:'short',timeStyle:'medium',hour12:true,timeZone:'America/Bogota'}).format(new Date());
  $('#updatedAt').textContent=DATA_UPDATED_AT;syncOptions();if(manual)resetDashboardFilters({status:'Instalado'});render()
 }catch(error){console.error('No se pudieron actualizar los datos del Sheet:',error);if(manual)alert('No se pudo consultar Google Sheets. Se mantienen los últimos datos disponibles.')}
 finally{if(button){button.disabled=false;button.textContent=original||'↻ Actualizar'}}
}
async function checkForAppUpdate(){
 try{
  const response=await fetch(VERSION_URL+'?cacheBust='+Date.now(),{cache:'no-store'});
  if(!response.ok)return false;
  const manifest=await response.json();
  if(!manifest.version||manifest.version===APP_VERSION)return false;
  const nextUrl=new URL(window.location.href);
  nextUrl.searchParams.set('appVersion',manifest.version);
  window.location.replace(nextUrl.toString());
  return true;
 }catch(error){console.warn('No se pudo comprobar la versión publicada:',error);return false}
}
