function parseDate(v){const s=clean(v);let m=s.match(/^(\d{4})-(\d{2})-(\d{2})/);if(m)return new Date(+m[1],+m[2]-1,+m[3]);m=s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})/);if(m)return new Date(+m[3],+m[2]-1,+m[1]);return null}
function unique(key,source=DATA){return [...new Set(source.map(d=>d[key]).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'es'))}
