 $('#providerChart').innerHTML=scope+(providers.length?providers.map(x=>'<div class="provider-item"><span>'+esc(x[0])+'</span><div class="track"><i style="width:'+x[1]/pm*100+'%"></i></div><b><span>'+fmt(x[1])+'</span><em>'+((x[1]/base)*100).toLocaleString('es-CO',{maximumFractionDigits:1})+'%</em></b></div>').join(''):'<p class="empty">No hay proveedores registrados para estos filtros.</p>');
