function renderSizes(){const panel=$('.school-size');if(currentOrg()==='foundation'){panel.style.display='none';return}panel.style.display='block';const rs=filtered().filter(d=>d.org==='education'&&Number(d.people)>0),order=['0–200','201–500','501–1.000','1.001–1.500','1.501–2.000','Más de 2.000'],counts=Object.fromEntries(order.map(x=>[x,0]));rs.forEach(d=>counts[sizeBucket(d)]++);const max=Math.max(1,...Object.values(counts));$('#sizeChart').innerHTML=order.map(k=>'<div class="size-row"><span>'+k+'</span><div class="track"><i style="width:'+counts[k]/max*100+'%"></i></div><b>'+counts[k]+'</b></div>').join('');const total=rs.length,avg=total?Math.round(rs.reduce((a,d)=>a+d.people,0)/total):0,ordered=rs.slice().sort((a,b)=>a.people-b.people),smallest=ordered[0],largest=ordered[ordered.length-1];$('#sizeSummary').innerHTML='<article><span>Promedio por escuela</span><b>'+fmt(avg)+'</b></article><article><span>Escuelas analizadas</span><b>'+fmt(total)+'</b></article><article><span>Escuela con menos alumnos</span><b>'+(smallest?fmt(smallest.people)+' alumnos':'0 alumnos')+'</b><small>'+(smallest?esc(smallest.institution)+(clean(smallest.site)?' · '+esc(smallest.site):''):'Sin resultados')+'</small></article><article><span>Escuela con más alumnos</span><b>'+(largest?fmt(largest.people)+' alumnos':'0 alumnos')+'</b><small>'+(largest?esc(largest.institution)+(clean(largest.site)?' · '+esc(largest.site):''):'Sin resultados')+'</small></article>'}
